function LuaEntityManager:getClientId(serverId)
    return DataCache[tostring(serverId)]
end

function LuaEntityManager:addEntity(entity)
    EntityList[tostring(entity.entityId)] = entity
    if isClient then
        DataCache[tostring(entity.serverId)] = entity.entityId
    end
end

function LuaEntityManager:subEntity(entityId)
    EntityList[tostring(entityId)] = nil
